// It will be available in the `items` variable.

// Get the JSON data from the first input item.
const inputJson = items[0].json;

// Handle both array and object inputs.
const dataObject = Array.isArray(inputJson) ? inputJson[0] : inputJson;

// Safely access the nested properties.
const rawText = dataObject?.content?.parts?.[0]?.text;

// Check if we successfully found the text.
if (!rawText) {
  throw new Error("Could not find 'text' property at the expected path (json.content.parts[0].text). Please verify the input data structure.");
}

// Use a regular expression to extract the pure HTML content.
const match = rawText.match(/```html\n([\s\S]+?)```/);

// Check if the HTML content was found.
if (!match || !match[1]) {
  throw new Error("Could not find HTML content in the input text. Make sure it's wrapped in ```html ... ```");
}

const htmlContent = match[1];
const fileName = "report.html";
const mimeType = 'text/html';

// --- FIX STARTS HERE ---
// Manually create the binary data object, bypassing all helper functions.
// This is compatible with all versions of n8n.

// 1. Create a Buffer from the HTML string.
const fileBuffer = Buffer.from(htmlContent, 'utf-8');

// 2. Convert the Buffer to a base64 encoded string.
const base64Data = fileBuffer.toString('base64');

// 3. Construct the final output item.
// The `binary` property must contain an object where the key (e.g., 'data')
// points to the object containing the base64 data and metadata.
return [{
  json: {
    fileName: fileName,
    status: 'HTML file created successfully using the manual method.',
    size: htmlContent.length,
  },
  binary: {
    // 'data' is the standard property name that downstream nodes look for.
    data: {
      data: base64Data,
      fileName: fileName,
      mimeType: mimeType,
    }
  }
}];
// --- FIX ENDS HERE ---

